INSERT INTO public.photos VALUES (21456, 'Palacio de Fuenclara 1918', '"Reparto de comida a los pobres y obreros sin trabajo, de los cuales socorre diariamente m‚Ēú√≠s de mil esta benem‚Ēú¬ģrita entidad". Escena situada en el patio de la casa de Fuenclara, acondicionada por el arzobispado en 1899 como sede de la Sociedad Protectora de J‚Ēú‚Ēāvenes Obreros y Comerciantes.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.65401400, -0.88212300, '0101000020E6100000C09481035A3AECBF259012BBB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52021455349.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52021455349.webp', 'https://www.flickr.com/photos/zaragozaantigua/52021455349/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21611, 'Sal‚Ēú‚Ēān Fuenclara c.1925', 'Imagen capturada en el interior del teatro Sal‚Ēú‚Ēān Fuenclara dise‚Ēú‚Ėíado por el arquitecto Francisco Albi‚Ēú‚Ėíana en la antigua casa de los condes de Fuenclara, sita en el n‚Ēú‚ēĎmero 2 de la hom‚Ēú‚Ēānima calle. Inaugurado en 1914 y gestionado por la cat‚Ēú‚Ēālica Sociedad Protectora de J‚Ēú‚Ēāvenes Obreros y Comerciantes, desde 1951 se dedicar‚Ēú¬°a exclusivamente a la exhibici‚Ēú‚Ēān de pel‚Ēú¬°culas ya como Cine Arlequ‚Ēú¬°n. Fuente visual: Francisco G‚Ēú‚Ēārriz, AMZ.', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65401400, -0.88212300, '0101000020E6100000C09481035A3AECBF259012BBB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30440832188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30440832188.webp', 'https://www.flickr.com/photos/zaragozaantigua/30440832188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21853, 'Calle de M‚Ēú¬ģndez N‚Ēú‚ēĎ‚Ēú‚Ėíez 1931', 'Imagen de la esquina de la calle de M‚Ēú¬ģndez N‚Ēú‚ēĎ‚Ēú‚Ėíez con la del Pino (hacia la derecha) y con la de las V‚Ēú¬°rgenes (hacia la izquierda), ubicaci‚Ēú‚Ēān desde finales del siglo XVI del Colegio de las V‚Ēú¬°rgenes, en la entonces calle de las Botigas Hondas. Entre 1853 y 1873 fue sede del Teatro Variedades. En el momento de realizar la foto era propiedad de Narciso Alfonso. Hacia 1943 el edificio, que conservaba retazos de su pasado conventual y teatral, fue derribado a finales de 1946 y sobre su solar se construyeron modernos bloques de vivienda. Fuente visual: www.mecd.gob.es/.', 1931, 1931, 1931, 'Anos 30', 'CENTRO', 41.65411000, -0.88027800, '0101000020E6100000DB6CACC43C2BECBF48FE60E0B9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35806169953.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35806169953.webp', 'https://www.flickr.com/photos/zaragozaantigua/35806169953/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22052, 'Pl. de San Felipe 1959', 'La plaza de San Felipe en una vista de su lado oeste comprendido entre la hom‚Ēú‚Ēānima iglesia parroquial, a la izquierda, y la calle de la Torre Nueva a la derecha. Destaca la fachada de la gran casa del siglo XVI que fuera de los Sanz de Cort‚Ēú¬ģs, luego de los marqueses de Villaverde, y ya en el siglo XIX de la condesa de Argillo. Tras pasar por diversas situaciones y usos, en esta fotograf‚Ēú¬°a el edificio era compartido por la delegaci‚Ēú‚Ēān provincial de la Organizaci‚Ēú‚Ēān Nacional de Ciegos (establecida en 1958) y el veterano Colegio de San Felipe. Esta plaza y su entorno estaban tambi‚Ēú¬ģn caracterizados por su destacado car‚Ēú√≠cter comercial. Fuente visual: Archivo Mora, en AMZ.', 1959, 1959, 1959, 'Anos 50', 'CENTRO', 41.65473900, -0.88207900, '0101000020E6100000D7A02FBDFD39ECBF3735D07CCED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897861907.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897861907.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897861907/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22069, 'Calle de Gil Berges 1953', 'Los Cabezudos Morico, Forano y Verrug‚Ēú‚Ēān comparsean la calle en el tranquilo tramo de los peques viviendo desde la calle Fuenclara (al fondo, a la izquierda). La imagen ha sido tomada en la calle Gil Berges, camino de la plaza de San Felipe. A la derecha, el callej‚Ēú‚Ēān de Torresecas. Gr‚Ēú√≠ficas Minerva, esquina la manzana del Palacio de Fuenclara. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1953, 1953, 1953, 'Anos 50', 'CENTRO', 41.65427600, -0.88227500, '0101000020E61000004182E2C7983BECBF6347E350BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15180921100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15180921100.webp', 'https://www.flickr.com/photos/zaragozaantigua/15180921100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22119, 'Florencio Mercadal 1956', 'Foto: Miguel Mar‚Ēú¬°n Chivite. Imagen del ‚Ēú‚ēĎltimo pajarero con puesto fijo en las calles de Zaragoza, Florencio Mercadal, en mayo de 1956. Estuvo vendiendo p‚Ēú√≠jaros en la plaza de Sas entre 1949 y, al menos, 1967. Vend‚Ēú¬°a canarios, periquitos, cardelinos y verderones, adem‚Ēú√≠s de conejos de Indias, gatos y perros. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65408300, -0.88101000, '0101000020E6100000E15D2EE23B31ECBF4EEFE2FDB8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22500992376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22500992376.webp', 'https://www.flickr.com/photos/zaragozaantigua/22500992376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22123, 'San Felipe c.1950', 'Plaza e iglesia parroquial de San Felipe. Detalle de la portada barroca. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1950, 1950, 1950, 'Anos 50', 'CENTRO', 41.65454000, -0.88215800, '0101000020E6100000DCF3FC69A33AECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22753564077.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22753564077.webp', 'https://www.flickr.com/photos/zaragozaantigua/22753564077/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22133, 'Calle Agustines 1951', 'Imagen capturada en la calle Fuenclara de una notable confluencia de viales: a la izquierda, la calle de Torresecas, medieval trenque abierto al Coso, luego cerrado, cuyo nombre proviene de la sobresaliente Casa de los Condes de Torres Secas, all‚Ēú¬° ubicada hasta su derribo. Al frente, el final de la calle de Agustines, que viene de la calle de la Audiencia, al fondo, antigua Subida de los Gigantes desde el Coso (otro trenque de la antigua muralla); a la derecha, la culminaci‚Ēú‚Ēān de la calle Gil Berges, que viene desde la plaza de San Felipe. Inmediata, a la izquierda, la esquina del antiguo palacio de Fuenclara a la calle Torresecas, que acog‚Ēú¬°a en sus bajos a la imprenta "Gr‚Ēú√≠ficas Minerva", junto a la "Farmacia Lasala", y a la "Librer‚Ēú¬°a Libros". Al otro lado de la calle, el nov‚Ēú¬°simo y chaflanero edificio del 6 de Agustines, entre la calle Torresecas y la desaparecida calle del Vicario. A la derecha, la esquinera casona del n‚Ē¨‚ēĎ 5 entre Gil Berges y Agustines, en cuyos bajos estaba la "Bola de Plata". En la calle Agustines, un pil‚Ēú‚Ēān de piedra disuasorio del paso de veh‚Ēú¬°culos. En la esquina de Gil Berges, un pil‚Ēú‚Ēān esquinero como defensa ante veh‚Ēú¬°culos. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65418200, -0.88245600, '0101000020E61000005516855D143DECBFE1D05B3CBCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23972032124.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23972032124.webp', 'https://www.flickr.com/photos/zaragozaantigua/23972032124/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22135, 'Calle Gil Berges 1951', 'La calle de Gil Berges form‚Ēú‚Ēā parte hasta bien entrado el siglo XX de la plaza de San Felipe, desde donde se ha tomado esta fotograf‚Ēú¬°a. A la izquierda, la manzana entre las calles de Candalija (antigua de Montera) y de Fuenclara, donde destaca el establecimiento comercial Pa‚Ēú‚Ėíos Sesma, que perdur‚Ēú‚Ēā hasta el siglo siguiente. Al fondo, la calle de Fuenclara y el hom‚Ēú‚Ēānimo palacio con la imprenta Gr‚Ēú√≠ficas Minerva en sus bajos. A continuaci‚Ēú‚Ēān, el callej‚Ēú‚Ēān de Torresecas, y a la derecha la irregular manzana de casonas entre las calles de Agustines y de Morata, en cuya esquina tuvo su primera sede la imprenta de Tom‚Ēú√≠s Blasco. Fuente visual: Juan Mora Insa, en AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65433400, -0.88228400, '0101000020E61000000D17B9A7AB3BECBF97546D37C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23974446423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23974446423.webp', 'https://www.flickr.com/photos/zaragozaantigua/23974446423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22307, 'Torre‚Ēú‚Ēān Fortea 1965', 'Archivo Municipal. Gerardo Sancho Ramo. 1965. "Iglesia de San Felipe, Torre‚Ēú‚Ēān Fortea y Museo de Pablo Gargallo". Imagen centrada en el macizo Torre‚Ēú‚Ēān Fortea. A la izquierda, la iglesia de San Felipe primero, y luego el Palacio de los Condes de Argillo, entonces sede del Colegio de San Felipe, y actual Museo de Pablo Gargallo (oculto tras la iglesia en la foto).', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65468300, -0.88206900, '0101000020E6100000F4177AC4E839ECBFA31F0DA7CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15642353835.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15642353835.webp', 'https://www.flickr.com/photos/zaragozaantigua/15642353835/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22318, 'Calle de Alfonso I 1968', 'Imagen del esplendor glorioso de una abundante iluminaci‚Ēú‚Ēān decorativa de esas que se instalan durante unas fechas muy se‚Ēú‚Ėíaladas del calendario, entre diciembre y enero. Esta decoraci‚Ēú‚Ēān lum‚Ēú¬°nica parece obrar sobre los humanos el efecto de la fototaxia en su versi‚Ēú‚Ēān consumista, pues suele aparecen sospechosamente en aquellas calles o zonas destacadas por su vertiente comercial, al efecto de inducir de forma sibilina a dejarse llevar por los insinuantes escaparates. Como se ve, a estas horas de la noche el ‚Ēú¬ģxito es arrollador, y no queda nadie en la calle, porque todos est‚Ēú√≠n dentro de los comercios comprando felicidad, y regando los brotes verdes de la macroeconom‚Ēú¬°a. O a lo mejor no hay nadie, y es un soberano despilfarro. Eso s‚Ēú¬°, precioso. Fuente: "Zaragoza viva" (1969)', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65458900, -0.88061200, '0101000020E610000086E28E37F92DECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15849888296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15849888296.webp', 'https://www.flickr.com/photos/zaragozaantigua/15849888296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22360, 'Gran Turismo 1967', 'Parada de taxis Gran Turismo en la plaza Sas. Se trataba de autom‚Ēú‚Ēāviles de alquiler de alta gama, que no llevaban tax‚Ēú¬°metro y se sol‚Ēú¬°an usar para bodas, celebraciones y viajes.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65398600, -0.88091300, '0101000020E610000043E1B3757030ECBF5C0531D0B5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21026402504.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21026402504.webp', 'https://www.flickr.com/photos/zaragozaantigua/21026402504/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22505, 'Calle de Alfonso I 1964', 'Estival imagen capturada desde la altura del inmueble del n‚Ē¨‚ēĎ 12 de la calle de Alfonso I, donde estaba ubicado el estudio fotogr‚Ēú√≠fico de Coyne, y centrada en el paso del cortejo oficial y tradicionalista encabezado, sobre mula blanca, por Pedro Cantero Cuadrado durante el ceremonial de toma de posesi‚Ēú‚Ēān como nuevo arzobispo de Zaragoza el d‚Ēú¬°a 16 de julio de 1964. Unos golpes de pezu‚Ēú‚Ėía antes y a caballo, el alcalde Luis G‚Ēú‚Ēāmez Laguna. En primer t‚Ēú¬ģrmino, fila de miembros de la Corporaci‚Ēú‚Ēān municipal, y a ambos lados del vial, numeroso p‚Ēú‚ēĎblico asistente, mientras vuelan miles de papelillos al sofocante aire arrojados fervorosa y organizadamente. De fondo, publicidad varia adosada a las vallas que delimitan el solar donde estuviera el antiguo inmueble del n‚Ē¨‚ēĎ 17, esquinero con los n‚Ēú‚ēĎmeros 5, 7 y 9 de la calle de Fuenclara, derribado pocos meses antes para embellecer este tramo de la calle.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65385100, -0.88137300, '0101000020E6100000207A52263534ECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50135958963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50135958963.webp', 'https://www.flickr.com/photos/zaragozaantigua/50135958963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22543, 'Joyer‚Ēú¬°a Aladr‚Ēú¬ģn c.1976', 'Foto Gonzalo Bull‚Ēú‚Ēān. Sucesor Joyer‚Ēú¬°a Aladr‚Ēú¬ģn (Jos‚Ēú¬ģ Lacruz L‚Ēú‚Ēāpez). Tienda en Alfonso I n‚Ē¨‚ēĎ 25, declarada Bien de Inter‚Ēú¬ģs Cultural, Gran Caf‚Ēú¬ģ Zaragoza desde septiembre de 1998. Fuente: www.rafaelcastillejo.com', 1976, 1976, 1976, 'Anos 70', 'CENTRO', 41.65467700, -0.88058600, '0101000020E61000003718EAB0C22DECBFC138B874CCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14939687490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14939687490.webp', 'https://www.flickr.com/photos/zaragozaantigua/14939687490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22552, 'Pl. de San Felipe c.1977', 'Desde 1860, el palacio de Argillo acogi‚Ēú‚Ēā en alquiler al Colegio de San Felipe. En 1943, el palacio fue declarado Monumento Nacional y, desde 1946, cambi‚Ēú‚Ēā de propietario y uso. La Organizaci‚Ēú‚Ēān Nacional de Ciegos Espa‚Ēú‚Ėíoles comparti‚Ēú‚Ēā espacios con el Colegio de San Felipe (trasladado en 1958). En 1970, la ONCE cambiaba tambi‚Ēú¬ģn de domicilio. En 1977 el Ayuntamiento de Zaragoza efectu‚Ēú‚Ēā la adquisici‚Ēú‚Ēān del edificio. Al tratarse de un Monumento Nacional, el Ministerio de Cultura financi‚Ēú‚Ēā algunas intervenciones de consolidaci‚Ēú‚Ēān para frenar su progresiva ruina. En 1979 se firm‚Ēú‚Ēā un convenio entre el Ministerio y el Ayuntamiento, encaminado a restaurar el edificio y utilizarlo como sede para talleres art‚Ēú¬°sticos. En la imagen, aspecto de la Plaza de San Felipe en las inmediaciones del Palacio de Argillo, a la derecha, y de la Iglesia de San Felipe, al fondo.', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65480000, -0.88237200, '0101000020E6100000DFFE5C34643CECBFDDB5847CD0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15028653690.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15028653690.webp', 'https://www.flickr.com/photos/zaragozaantigua/15028653690/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22660, 'Plaza San Felipe 1977', 'Plaza e iglesia parroquial de San Felipe. A la izquierda, la calle Gil Berges. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1977, 1977, 1977, 'Anos 70', 'CENTRO', 41.65454000, -0.88215800, '0101000020E6100000DCF3FC69A33AECBF40F67AF7C7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22523851803.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22523851803.webp', 'https://www.flickr.com/photos/zaragozaantigua/22523851803/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22741, 'Calle de Alfonso I 1979', 'Vista de la calle de Alfonso I desde su esquina con la plaza de Sas (izquierda). Al fondo, el Coso Alto. A la derecha, grandes almacenes Gay, tras el Hotel Europa. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 1979, 1979, 1979, 'Anos 70', 'CENTRO', 41.65403600, -0.88129800, '0101000020E610000077F700DD9733ECBF0D349F73B7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31652079893.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31652079893.webp', 'https://www.flickr.com/photos/zaragozaantigua/31652079893/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22856, 'Gil Berg‚Ēú¬ģs A‚Ēú‚Ėíos 80', 'Imagen del peque‚Ēú‚Ėío edificio de vivienda (antiguo n‚Ē¨‚ēĎ 5, luego n‚Ē¨‚ēĎ 1) que hac‚Ēú¬°a esquina entre las calles de Gil Berges y la de Agustines, cerca de la plaza de San Felipe. Construido en arquitectura tradicional, como la de otros edificios de la zona, es muy probable que su original planta fuera del XVII, con remodelaciones posteriores. Presentaba una interesante galer‚Ēú¬°a de arquillos, o mirador, bajo alero o cornisa. A diferencia de esos otros edificios, ‚Ēú¬ģste fue piqueteado en 1997, y en su lugar hay desde entonces un solar. En la imagen, dibujo recreando el edificio, cuando en sus bajos acog‚Ēú¬°a un negocio de solera: la churrer‚Ēú¬°a "Bola de Plata". Fuente: www.facebook.com/photo.php?fbid=600342463428476&set=p...', 1980, 1980, 1989, 'Anos 80', 'CENTRO', 41.65426800, -0.88253200, '0101000020E6100000158DB5BFB33DECBFE068C70DBFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15601187499.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15601187499.webp', 'https://www.flickr.com/photos/zaragozaantigua/15601187499/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22861, 'Torre‚Ēú‚Ēān Fortea 1987', 'Luis M‚Ēú¬°nguez. 1987. Desde la singular torre de iglesia de San Felipe, esquivando levemente la oscura campana, un vistazo hacia el Norte, en la medida de lo posible. En primer plano, la vegetaci‚Ēú‚Ēān de la inmediata plaza de San Felipe, y el macizo torre‚Ēú‚Ēān Fortea, a la izquierda. Por uno de sus vanos nos podemos trasladar hasta el otro lado del Ebro, y llegar a Valle de Broto (la calle). A la derecha, la torre de Santiago de la bas‚Ēú¬°lica del Pilar.', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65454900, -0.88237100, '0101000020E6100000C80A7E1B623CECBF9450FA42C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15656533430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15656533430.webp', 'https://www.flickr.com/photos/zaragozaantigua/15656533430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22868, 'Torre Nueva 1989', 'Imagen del pie de la Torre Nueva de Zaragoza, sacado a la luz en las excavaciones arqueol‚Ēú‚Ēāgicas realizadas en 1988 y 1989.', 1989, 1989, 1989, 'Anos 80', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15750348182.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15750348182.webp', 'https://www.flickr.com/photos/zaragozaantigua/15750348182/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22944, 'Pl. de San Felipe 1987', 'Foto: Tom‚Ēú√≠s Mora Ruata. Vista de la plaza de San Felipe en 1987. A la derecha, obras de restauraci‚Ēú‚Ēān del Torre‚Ēú‚Ēān Fortea, antigua casa de los Cerd‚Ēú√≠n de Escatr‚Ēú‚Ēān, adquirida por el Ayuntamiento en 1981. En 1991 se remodelar‚Ēú√≠ la plaza. Fuente: www.facebook.com/photo.php?fbid=1810357708992339&set=...', 1987, 1987, 1987, 'Anos 80', 'CENTRO', 41.65472200, -0.88213500, '0101000020E6100000D105F52D733AECBF61FC34EECDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36622101730.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36622101730.webp', 'https://www.flickr.com/photos/zaragozaantigua/36622101730/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22979, 'Memorial de la Torre Nueva c.1995', 'El monumento que preside la foto, levantado sobre el per‚Ēú¬°metro original de la Torre Nueva de Zaragoza en la plaza de San Felipe, junto al Torre‚Ēú‚Ēān Fortea, fue erigido en 1991, al acometer el Ayuntamiento la remodelaci‚Ēú‚Ēān de la plaza. En marzo de 2002 fue derribado. Queda en el suelo el recuerdo de la forma del s‚Ēú‚Ēātano de la torre, seg‚Ēú‚ēĎn la excavaci‚Ēú‚Ēān arqueol‚Ēú‚Ēāgica. Tambi‚Ēú¬ģn, a su lado, la estatua sedente en bronce de un ni‚Ēú‚Ėío que mira hacia lo alto del fantasma del antiguo campanario civil exento. Fuente visual: www.placesonline.es/europa/espana/aragon/zaragoza/detalle...', 1995, 1995, 1995, 'Anos 90', 'CENTRO', 41.65475900, -0.88206200, '0101000020E6100000556B6116DA39ECBF7EE19524CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15697777472.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15697777472.webp', 'https://www.flickr.com/photos/zaragozaantigua/15697777472/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22995, 'Calle de Alfonso I 1992', 'El n‚Ē¨‚ēĎ 18 de la calle Alfonso I, construido a la par que el n‚Ē¨‚ēĎ 20, y recayente a la calle M‚Ēú¬ģndez N‚Ēú‚ēĎ‚Ēú‚Ėíez, forma parte de las nuevas construcciones a la carta realizadas para adaptarse a los gustos ecl‚Ēú¬ģcticos de la nueva y burguesa calle. A mediados de los a‚Ēú‚Ėíos 20 del pasado siglo, su planta baja, a la izquierda del portal de ingreso, fue acondicionada para la "Librer‚Ēú¬°a y Papeler‚Ēú¬°a Aperte", resultando uno de los locales comerciales m‚Ēú√≠s interesantes de la ciudad por su infrecuente traza racionalista con decoraciones "art d‚Ēú¬ģco". Madera, vidrier‚Ēú¬°a, rejer‚Ēú¬°a, y m‚Ēú√≠rmoles, compon‚Ēú¬°an una singular fachada, acompa‚Ēú‚Ėíada en el interior de una decoraci‚Ēú‚Ēān y mobiliario congruentes. En 1993, la firma comercial "Aperte" cerr‚Ēú‚Ēā, y el local fue remodelado a los gustos postmodernos de la ‚Ēú¬ģpoca, resultando lo que hoy hay en su lugar, en tono banana. La imagen captura el estado del local, antes de su transfiguraci‚Ēú‚Ēān.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65445500, -0.88066400, '0101000020E61000002577D844662EECBF12DA722EC5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23118237906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23118237906.webp', 'https://www.flickr.com/photos/zaragozaantigua/23118237906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22999, 'Pasaje de los Giles a‚Ēú‚Ėíos 90', 'Vista del interior del Pasaje de los Giles a finales del siglo XX. Este espacio fue cerrado poco despu‚Ēú¬ģs de ser tomada la imagen y reabierto ya en el siglo XXI. La terraza hostelera corresponde a la Horchater‚Ēú¬°a Miguel, enclavada en la entrada del pasaje por la calle de los Est‚Ēú¬ģbanes (al fondo a la derecha).', 1990, 1990, 1999, 'Anos 90', 'CENTRO', 41.65371400, -0.88070900, '0101000020E6100000245F09A4C42EECBFFB777DE6ACD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26437747201.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26437747201.webp', 'https://www.flickr.com/photos/zaragozaantigua/26437747201/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23013, 'Torre Nueva 1991', 'El Ayuntamiento de la ciudad aprob‚Ēú‚Ēā en 1990 un proyecto de Memorial o monumento conmemorativo de la Torre Nueva a construir en la plaza de San Felipe, consistente en el recrecimiento parcial en ladrillo del n‚Ēú‚ēĎcleo interior de la Torre Nueva, con un remate en forma helicoidal e inacabada que remarcaba el derribo padecido en 1892. Adem‚Ēú√≠s, unos paneles de albino m‚Ēú√≠rmol de Macael perfilaban la planta estrellada que caracterizaba el arranque de la Torre. Entre dos de esos paneles fueron colocadas unas puertas de bronce con un alto relieve de la Torre, y una inscripci‚Ēú‚Ēān informativa. Desencuentros administrativos producidos entre el Ayuntamiento y la Direcci‚Ēú‚Ēān General de Patrimonio Cultural y Educaci‚Ēú‚Ēān de la DGA, desde el principio mismo del proyecto, desembocaron en un largo proceso judicial que culmin‚Ēú‚Ēā en la Sentencia 388/1998 del Tribunal Superior de Justicia de Arag‚Ēú‚Ēān, que declaraba la ilegalidad de las obras ejecutadas e inauguradas en 1991, se‚Ēú‚Ėíalando que habr‚Ēú¬°an de demolerse por perturbar la contemplaci‚Ēú‚Ēān de bienes de Inter‚Ēú¬ģs Cultural como el Torre‚Ēú‚Ēān Fortea. En marzo de 2002 la referida Sentencia fue cumplida, y se procedi‚Ēú‚Ēā a la demolici‚Ēú‚Ēān del Memorial. En la imagen, puertas de bronce del Memorial de la Torre Nueva, inaugurado en 1991 y demolido por Sentencia en 2002, si bien perdura el bronc‚Ēú¬°neo "mir‚Ēú‚Ēān" dise‚Ēú‚Ėíado por Santiago Gimeno Llop que en la plaza de San Felipe mantiene la vista, de forma perenne, en el ectoplasma de la desaparecida Torre Nueva de Zaragoza. La figura de la Torre se corresponde con la etapa en que estaba coronada por un triple chapitel barroco, instalado en 1749 y desmontado en 1878 como paso previo a la demolici‚Ēú‚Ēān de 1892. Es la imagen "cl‚Ēú√≠sica" de esta singular y perdida atalaya urbana. Fuente visual: revista "Arag‚Ēú‚Ēān tur‚Ēú¬°stico y monumental", SIPA.', 1991, 1991, 1991, 'Anos 90', 'CENTRO', 41.65488800, -0.88204800, '0101000020E6100000171230BABC39ECBF7C45B75ED3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34058280224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34058280224.webp', 'https://www.flickr.com/photos/zaragozaantigua/34058280224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23028, 'Plaza de San Felipe 1992', 'A finales de los a‚Ēú‚Ėíos ochenta el Ayuntamiento impuls‚Ēú‚Ēā el plan "Zaragoza 1992" que incluy‚Ēú‚Ēā actuaciones en el casco hist‚Ēú‚Ēārico para rehabilitar su imagen al hilo del evento que conmemoraba el quinto centenario de 1492. De esta forma, varias plazas, entre ellas la de San Felipe, fueron objeto de una intervenci‚Ēú‚Ēān urban‚Ēú¬°stica para renovar su aspecto, que en este caso incluy‚Ēú‚Ēā el Memorial de la Torre Nueva complementado de forma no prevista por el bronce titulado Muchacho sentado mirando a la Torre Nueva, y otros motivos simb‚Ēú‚Ēālicos y gr‚Ēú√≠ficos asociados al recuerdo de esta referencial atalaya derribada a finales del siglo XIX. Una orden judicial supuso la eliminaci‚Ēú‚Ēān del memorial en 2002, y el vandalismo urbano acab‚Ēú‚Ēā con los motivos simb‚Ēú‚Ēālicos y gr‚Ēú√≠ficos, dejando "colgada" a la escultura realizada por Santiago Gimeno Llop que, en estas circunstancias, dirige su mirada hacia el espacio que ocupaba la Torre Nueva, aunque por supuesto no hay ninguna referencia que lo explique para quien se tope literalmente con ella. En la imagen, aspecto de la plaza tras su renovaci‚Ēú‚Ēān y en un d‚Ēú¬°a lluvioso, con el fondo de la iglesia de San Felipe, el palacio de Argillo, el Memorial de la Torre Nueva observado por el bronc‚Ēú¬°neo muchacho sentado en el suelo, y la casa-torre‚Ēú‚Ēān de los Fortea.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65465300, -0.88203900, '0101000020E61000004A7D59DAA939ECBF399D64ABCBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50204841172.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50204841172.webp', 'https://www.flickr.com/photos/zaragozaantigua/50204841172/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23030, 'Calle de Alfonso I 1992', 'Calle de Alfonso I, en una vista tomada a la altura de la de Casto M‚Ēú¬ģndez N‚Ēú‚ēĎ‚Ēú‚Ėíez, a la derecha. La configuraci‚Ēú‚Ēān de este vial todav‚Ēú¬°a est‚Ēú√≠ preparada para el tr‚Ēú√≠fico rodado, con dos carriles de circulaci‚Ēú‚Ēān. En el firme, las indicaciones llevan a continuar hasta la plaza del Pilar, o a girar a la izquierda por la calle de la Torre Nueva hasta el Mercado Central. En 2001, esta calle comercial ser‚Ēú√≠ remodelada y peatonalizada.', 1992, 1992, 1992, 'Anos 90', 'CENTRO', 41.65433900, -0.88091200, '0101000020E61000002DEDD45C6E30ECBFA9BF5E61C1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207270752.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207270752.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207270752/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23097, 'Calle de Alfonso I 2000', 'Aspecto de la manifestaci‚Ēú‚Ēān contra el trasvase del Ebro del Plan Hidrol‚Ēú‚Ēāgico Nacional, el domingo 8 de octubre de 2000, a su paso por la calle de Alfonso I. Al fondo, el Coso Alto. Fuente: "Trabajo, sociedad, cultura. Una mirada al siglo XX en Arag‚Ēú‚Ēān", UGT, 2000.', 2000, 2000, 2000, 'Siglo XXI', 'CENTRO', 41.65441900, -0.88091300, '0101000020E610000043E1B3757030ECBFC5707500C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23641831323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23641831323.webp', 'https://www.flickr.com/photos/zaragozaantigua/23641831323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23110, 'Calle de Alfonso I 2006', 'S‚Ēú√≠bado 4 de noviembre de 2006. Manifestaci‚Ēú‚Ēān contra la OTAN en Zaragoza, "Por una cultura de la paz, hace 20 a‚Ēú‚Ėíos y ahora", en alusi‚Ēú‚Ēān a las movilizaciones contra la Organizaci‚Ēú‚Ēān del Tratado del Atl‚Ēú√≠ntico Norte que se produjeron en 1986, a‚Ēú‚Ėío del refer‚Ēú¬ģndum sobre la permanencia de Espa‚Ēú‚Ėía. Esta vez, en contra de la instalaci‚Ēú‚Ēān de la sede del Sistema de Vigilancia A‚Ēú¬ģrea de Superficie (AGS) de la OTAN en suelo zaragozano. La oposici‚Ēú‚Ēān ciudadana, pese al apoyo del gobierno socialista aragon‚Ēú¬ģs, fue uno de los motivos por los que esta sede no acab‚Ēú‚Ēā en la ciudad, estando prevista su instalaci‚Ēú‚Ēān en Sicilia. En la foto, cabecera de la manifestacion, en el tramo de la calle de Alfonso I entre Cuatro de Agosto y la plaza de Sas. El domingo 21 de enero de 2007 hubo otra manifestaci‚Ēú‚Ēān con el mismo prop‚Ēú‚Ēāsito. Fuente: Agencia EFE.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65388200, -0.88139600, '0101000020E61000002B685A626534ECBFB7B8C667B2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24772919305.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24772919305.webp', 'https://www.flickr.com/photos/zaragozaantigua/24772919305/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23118, 'Calle Jussepe Mart‚Ēú¬°nez 2006', 'Foto: Jos‚Ēú¬ģ Miguel Marco. Andamio colocado en los n‚Ēú‚ēĎmeros 9 al 13 de la calle de Jussepe Mart‚Ēú¬°nez, que permaneci‚Ēú‚Ēā colocado all‚Ēú¬° durante once a‚Ēú‚Ėíos, desde 1999 hasta 2010. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65438500, -0.87987300, '0101000020E6100000E144F46BEB27ECBF19FF3EE3C2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31100003844.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31100003844.webp', 'https://www.flickr.com/photos/zaragozaantigua/31100003844/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23125, 'Calle de Fuenclara 2006', 'Foto: Jos‚Ēú¬ģ Miguel Marco. Aspecto de las obras de restauraci‚Ēú‚Ēān a lo largo de 2006 de la fachada y la cubierta del palacio de Fuenclara, en la calle hom‚Ēú‚Ēānima. La restauraci‚Ēú‚Ēān integral y apertura al p‚Ēú‚ēĎblico estaban previstas para 2008. En 2017 no se hab‚Ēú¬°an producido. Fuente: Heraldo de Arag‚Ēú‚Ēān.', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.65412100, -0.88235200, '0101000020E610000018EDF1423A3CECBF3C50A73CBAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31180618813.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31180618813.webp', 'https://www.flickr.com/photos/zaragozaantigua/31180618813/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22802, 'Calle de Violante de Hungr‚Ēú¬°a 1976', 'Imagen capturada desde la altura del moderno inmueble del n‚Ē¨‚ēĎ 8 de la calle de Luis Bermejo, y centrada en el Pabell‚Ēú‚Ēān Municipal de Deportes durante su proceso de construcci‚Ēú‚Ēān en la parcela delimitada por las calles de Violante de Hungr‚Ēú¬°a, de los Condes de Arag‚Ēú‚Ēān, y la referida de Luis Bermejo. El poblado ferial del fondo, en el que destaca la carpa del Circo Atlas, indica la realizaci‚Ēú‚Ēān de esta toma durante las fiestas mayores de la ciudad, en octubre. Al fondo, la Escuela de Idiomas, dependencias traseras del Hospital Cl‚Ēú¬°nico Universitario, y Campus de la Universidad, con el solar donde luego se construir‚Ēú¬°a la nueva Facultad de Medicina, adem‚Ēú√≠s de la gran pista de equitaci‚Ēú‚Ēān de los terrenos de La H‚Ēú¬°pica.', 1976, 1976, 1976, 'Anos 70', 'UNIVERSIDAD', 41.63974100, -0.90397900, '0101000020E610000043AA285E65EDECBF86747808E3D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/47942666627.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/47942666627.webp', 'https://www.flickr.com/photos/zaragozaantigua/47942666627/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23214, 'Calle de Contamina 2017', 'Imagen capturada durante el derribo de tres antiguos inmuebles en la esquina de las calles de Contamina (el n‚Ē¨‚ēĎ 14, y el n‚Ē¨‚ēĎ 16), y la de Mat‚Ēú¬°as Carrica (el n‚Ē¨‚ēĎ 11-13). La imagen se centra en el esquinero n‚Ē¨‚ēĎ 16 de Contamina. Hacia la derecha se abre la antigua calle de Luna/de la Luna, desde 1942 redenominada Maestro Luna. El derribo de estos inmuebles, de propiedad municipal, fue aprobado tiempo ha al objeto de &quot;esponjar&quot; esta zona del Casco Antiguo de la ciudad y habilitar un solar como espacio de encuentro ciudadano a 70 m. de la plaza de San Felipe, 135 m. de la plaza del Justicia y 140 m. de la plaza de Sas. Los tres inmuebles, al no tener antecedentes de prestigio edilicio, o de fama positiva asociada a ellos, no estaban catalogados y fueron retirados del escenario urbano en el tr‚Ēú√≠nsito del a‚Ēú‚Ėío 2016 al 2017. El participativo solar resultante cuenta con la protecci‚Ēú‚Ēān simb‚Ēú‚Ēālica de dos c‚Ēú‚Ēārvidos rupestres, bidimensionales y solitarios. Fuente visual: foto Jos‚Ēú¬ģ Mar‚Ēú¬°a Ballest‚Ēú¬°n Miguel', 2017, 2017, 2017, 'Siglo XXI', 'CENTRO', 41.65502700, -0.88118200, '0101000020E6100000295DFA97A432ECBF9D7FBBECD7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36570908822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36570908822.webp', 'https://www.flickr.com/photos/zaragozaantigua/36570908822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23221, 'Callej‚Ēú‚Ēān de Torres Secas 2019', 'Imagen promocional de la pel‚Ēú¬°cula "Las ni‚Ēú‚Ėías" dirigida por Pilar Palomero y rodada en localizaciones de Zaragoza. En este caso, las ni‚Ēú‚Ėías protagonistas de la cinta (de izquierda a derecha: "Clara", Ainara Nieto; "Leyre", Elisa Mart‚Ēú¬°nez; "Brisa", Zoe Arnao; "Cristina", Julia Sierra; "Vanessa", Carlota Gurpegui; y "Celia", Andrea Fandos) posan en la antigua calle de Torres Secas, convertida en callej‚Ēú‚Ēān desde que se cerr‚Ēú‚Ēā el ingreso desde el Coso Alto, y que recuerda a la desaparecida y hom‚Ēú‚Ēānima casa de los condes de Torres Secas. Al fondo, puerta azul que conserva en su parte superior la inscripci‚Ēú‚Ēān "Jos‚Ēú¬ģ Alfonso" por dar acceso trasero a este veterano establecimiento de drogas. A la izquierda y fuera de plano queda el palacio de Fuenclara, y a la derecha aparecen pegados a la pared, para dar la ambientaci‚Ēú‚Ēān requerida de principios de los pr‚Ēú‚Ēādigos a‚Ēú‚Ėíos 90, cuando transcurre la trama de esta pel‚Ēú¬°cula, varios carteles de los exitosos y locales grupos de m‚Ēú‚ēĎsica popular del momento: H‚Ēú¬ģroes del Silencio (su LP de 1990, "Senderos de traici‚Ēú‚Ēān" y Ni‚Ēú‚Ėíos del Brasil (su LP de 1993, "Mundos en eclipse").', 2019, 2019, 2019, 'Siglo XXI', 'CENTRO', 41.65402000, -0.88261800, '0101000020E6100000B98C9B1A683EECBF087767EDB6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50843609408.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50843609408.webp', 'https://www.flickr.com/photos/zaragozaantigua/50843609408/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23225, 'Plaza San Felipe 2016', 'El 3 de diciembre de 2016 se inaugur‚Ēú‚Ēā en la plaza de San Felipe √Ē√á¬£El quiosco. Mapas de Poder en Zaragoza√Ē√á√ė, que permaneci‚Ēú‚Ēā all‚Ēú¬° durante dos semanas. Se trataba de un puesto callejero en el que se repart‚Ēú¬°an distintas publicaciones informativas respecto a la iniciativa √Ē√á¬£Qui‚Ēú¬ģn manda en Zaragoza√Ē√á√ė, puesta en marcha por el colectivo A Zofra. Esas publicaciones inclu‚Ēú¬°an estudios detallados sobre el verdadero poder local, con la colaboraci‚Ēú‚Ēān de 20 artistas pl‚Ēú√≠sticos, entre los que se encontraba Jos‚Ēú¬ģ Luis Cano. En la foto, vista del citado quiosco, con la calle de Antonio Candalija al fondo.', 2016, 2016, 2016, 'Siglo XXI', 'CENTRO', 41.65473300, -0.88202800, '0101000020E61000005000C5C89239ECBF554E7B4ACED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52461017984.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52461017984.webp', 'https://www.flickr.com/photos/zaragozaantigua/52461017984/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23777, 'Torre de Santa Engracia 1935', 'Imagen de la fachada del cuadrangular y recio edificio principal de la Torre de Santa Engracia, en el barrio de Movera, construida en el siglo XVII como propiedad del monasterio jer‚Ēú‚Ēānimo de Santa Engracia, y decorada con llamativos medallones. En el momento de realizar esta captura, posiblemente estaba siendo utilizado como casa de labor propiedad de la familia Casa‚Ēú‚Ėía. Se accede a ella desde un antiguo camino vecinal, luego carretera, que une Movera con Pastriz, propiedad de la DPZ. Fuente visual: foto Juan Mora Insa, en AHPZ.', 1935, 1935, 1935, 'Anos 30', NULL, 41.64234700, -0.80543500, '0101000020E610000067B8019F1FC6E9BF84D72E6D38D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33289545192.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33289545192.webp', 'https://www.flickr.com/photos/zaragozaantigua/33289545192/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23277, 'Plaza de Sas 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/enero 1966. Imagen de la Plaza de Sas tomada desde la calle Antonio Candalija. Un poco antes de la calle Est‚Ēú¬ģbanes, captura del edificio que all‚Ēú¬° se levantaba a‚Ēú‚ēĎn en los a‚Ēú‚Ėíos del desarrollismo franquista, con tienda de "Helados" y una "Oficina de viajes" haciendo esquina Blas‚Ēú‚Ēān Aragon‚Ēú¬ģs. Planta de palacete renacentista a la zaragozana (en ladrillo), bien majo, robusto, y con uno de esos aleros de madera tan superlativos. Con las modas del barroco, se puso a la moda est‚Ēú¬ģtica de la ‚Ēú¬ģpoca, con una espectacular decoraci‚Ēú‚Ēān de la puerta principal de ingreso, siendo ya la casona de los barones de La Linde, en la de toda la vida plaza del Carb‚Ēú‚Ēān. Llegados a finales de los sesenta del siglo pasado, este edificio ten‚Ēú¬°a una grave deficiencia: poco aprovechamiento vertical. Los propietarios actuaron para remediarlo, y el resultado salta a la vista hoy: ya no est‚Ēú√≠, sustituido por uno de esos horrores contempor‚Ēú√≠neos que plaguean el casco hist‚Ēú‚Ēārico de la ciudad. Casi todos los dem‚Ēú√≠s de la plaza, retocados en mayor o menor grado, perduran. Y los coches han volado.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65380300, -0.88069700, '0101000020E610000013EE9579AB2EECBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664590659.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664590659.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664590659/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23280, 'Plaza de Sas 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/enero 1966. Imagen de la Plaza de Sas tomada desde la calle Antonio Candalija. Un poco antes de la calle Est‚Ēú¬ģbanes, al fondo a la derecha, captura del antiguo palacio de los barones de La Linde, con tienda de "Helados" y una "Oficina de viajes" haciendo esquina con la calle Blas‚Ēú‚Ēān Aragon‚Ēú¬ģs. Para mucha gente, lo m‚Ēú√≠s importante de esta imagen son los coches, los helados, y las veces que han pasado por esta antigua plaza del Carb‚Ēú‚Ēān.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65386700, -0.88071900, '0101000020E610000008E8BE9CD92EECBF8177F2E9B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14848098031.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14848098031.webp', 'https://www.flickr.com/photos/zaragozaantigua/14848098031/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23281, 'Plaza de Sas 1966', 'Imagen de la antigua plaza del Carb‚Ēú‚Ēān, luego redenominada de Sas, tomada desde la calle Alfonso I. A la derecha de la embocadura con la calle Est‚Ēú¬ģbanes, captura del edificio que albergaba al antiguo e irrepetible palacio de los barones de La Linde, entonces modernizado en sus bajos con una tienda de "Helados" y una "Oficina de viajes" en la esquina con la calle Blas‚Ēú‚Ēān Aragon‚Ēú¬ģs. Su escaso aprovechamiento vertical, y su mal gusto provinciano, muy reprochable para una ciudad tan cosmopolita como Zaragoza, fueron defectos radicalmente remediados a‚Ēú‚Ėíos despu‚Ēú¬ģs: fue demolido, y sustituido por otra cosa. Los dem‚Ēú√≠s edificios de esta plaza, si bien retocados en mayor o menor grado, perduran. Fuente visual: Gerardo Sancho Ramo, Archivo P‚Ēú‚ēĎblico Municipal.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.65385100, -0.88080500, '0101000020E6100000ABE7A4F78D2FECBF7CBABA63B1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14871079983.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14871079983.webp', 'https://www.flickr.com/photos/zaragozaantigua/14871079983/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23283, 'Calle de Alfonso I c.1968', 'Calle de Alfonso I; microb‚Ēú‚ēĎs.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65368500, -0.88145900, '0101000020E6100000C4793881E934ECBF617138F3ABD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14894510046.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14894510046.webp', 'https://www.flickr.com/photos/zaragozaantigua/14894510046/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24356, 'Romareda 1974', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. 18/02/1974. El Pol‚Ēú¬°gono Romareda va tomando forma con una perspectiva estilo Brasilia. Imagen tomada desde As‚Ēú¬°n y Palacios, con la nueva Parroquia de Santa M‚Ēú‚Ēānica a la derecha.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63729600, -0.90443500, '0101000020E6100000C5724BAB21F1ECBF91EF52EA92D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14948526402.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14948526402.webp', 'https://www.flickr.com/photos/zaragozaantigua/14948526402/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23286, 'Plaza de Sas 1965', 'Imagen de la antigua plaza del Carb‚Ēú‚Ēān, redenominada de Sas, capturada desde cierta altura de la calle Alfonso I, con la parafernalia de la "Cofrad‚Ēú¬°a de las Siete Palabras y de San Juan Evangelista." A la izquierda, esquinero con la calle del Pino (antigua continuaci‚Ēú‚Ēān de la calle de las V‚Ēú¬°rgenes), el n‚Ē¨‚ēĎ 4 de la plaza, obra de Jos‚Ēú¬ģ de Yarza en trazas modernistas de principios del siglo, para vivienda de Antonio Mar‚Ēú¬°a de Tro. Ocupado d‚Ēú¬ģcadas despu‚Ēú¬ģs por el femenino Liceo Hispano, fue convenientemente demolido a finales de los a‚Ēú‚Ėíos 70, y sustituido por otra cosa. La actual. Fuente visual: Estudio Coyne (AHPZ-DARA).', 1965, 1965, 1965, 'Anos 60', 'CENTRO', 41.65380300, -0.88069700, '0101000020E610000013EE9579AB2EECBF6B8313D1AFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15118110745.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15118110745.webp', 'https://www.flickr.com/photos/zaragozaantigua/15118110745/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23289, 'Colegio de las V‚Ēú¬°rgenes 1850', 'Litograf‚Ēú¬°a dibujada por J. B. Waring y publicada en Londres, 1850. Colegio de las V‚Ēú¬°rgenes con su caracter‚Ēú¬°stico torre‚Ēú‚Ēān, en la esquina de las calles V‚Ēú¬°rgenes (al fondo) y Torre Nueva (puerta de ingreso, a la derecha). La vista es desde la calle del Pino,', 1850, 1850, 1850, 'Siglo XIX', 'CENTRO', 41.65410000, -0.88014600, '0101000020E61000002191B6F1272AECBF24287E8CB9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19318235528.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19318235528.webp', 'https://www.flickr.com/photos/zaragozaantigua/19318235528/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23302, 'Calle de Alfonso I 1968', 'Sesentera imagen de una canicular tarde en la calle de Alfonso I, en la acera de los pares, manzana entre la calle Jussepe Mart‚Ēú¬°nez (antigua de Goya), y la de Casto M‚Ēú¬ģndez N‚Ēú‚ēĎ‚Ēú‚Ėíez (al frente). Inmediata, la veterana y Art Dec‚Ēú‚Ēā "Librer‚Ēú¬°a y Papeler‚Ēú¬°a Aperte". Por la acera, desfile de lacas, cardados y vol‚Ēú‚ēĎmenes locos en las se‚Ēú‚Ėíoras a la moda del momento. Al fondo, el Coso Alto con la original sede del Banco de Arag‚Ēú‚Ēān, ya despejado de su ruidoso y recordado remate sireno. Fuente: "Zaragoza Viva" (1969).', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65446300, -0.88070700, '0101000020E6100000F7764B72C02EECBF95B88E71C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24245710180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24245710180.webp', 'https://www.flickr.com/photos/zaragozaantigua/24245710180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23781, 'Acampo de Funes 2009', 'Vista a‚Ēú¬ģrea del antiguo acampo de Funes, con el pol‚Ēú¬°gono industrial Empresarium de La Cartuja Baja a la izquierda, y el Parque Tecnol‚Ēú‚Ēāgico de Reciclado L‚Ēú‚Ēāpez Soriano a la derecha. Abajo, el Canal Imperial de Arag‚Ēú‚Ēān. Fuente: APUDEPA, en www.revistadepatrimonio.es', 2009, 2009, 2009, 'Siglo XXI', NULL, 41.59267100, -0.82689200, '0101000020E6100000785E2A36E675EABFD124B1A4DCCB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40078000131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40078000131.webp', 'https://www.flickr.com/photos/zaragozaantigua/40078000131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23304, 'Calle de Alfonso I 1964', 'Imagen del ya tradicional ese a‚Ēú‚Ėío (como desde 1948) "paso de la tercera palabra", por la "cofrad‚Ēú¬°a de las siete palabras y de san Juan evangelista", el viernes 8 de abril de ese a‚Ēú‚Ėío. La procesionaria se localiza en la calle de Alfonso I. A la izquierda, m‚Ēú√≠s que interesante captura del derribo de la antigua finca de los n‚Ēú‚ēĎmeros 5-7-9 de la calle Fuenclara, y 17 de Alfonso I, que apenas contaba con un siglo de antig‚Ēú‚ēĚedad, y que fue construida cuando la apertura de esta reciente calle. Sobre su amplio solar estaba proyectado el nuevo establecimiento de los familiares y grandes almacenes "GAY", especialistas de art‚Ēú¬°culos del hogar y moda, que se inaugurar‚Ēú¬°a el a‚Ēú‚Ėío siguiente. Este edificio fue pionero en la tipolog‚Ēú¬°a vertical y opaca que los nuevos grandes centros comerciales de la ciudad seguir‚Ēú¬°an durante las siguientes d‚Ēú¬ģcadas. A la derecha, soleada, la plaza de Sas, antigua del Carb‚Ēú‚Ēān. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65372500, -0.88147900, '0101000020E61000008B8BA3721335ECBFEFC9C342ADD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26120855024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26120855024.webp', 'https://www.flickr.com/photos/zaragozaantigua/26120855024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23309, 'Plaza de Sas 1964', 'Imagen de la plaza de Sas, antigua del Carb‚Ēú‚Ēān, durante el paso de la Cofrad‚Ēú¬°a de las Siete Palabras y de San Juan Evangelista. La toma est‚Ēú√≠ centrada en el soleado tramo de los pares, donde destaca el edificio n‚Ē¨‚ēĎ 4, esquinero con la calle del Pino, obra de Jos‚Ēú¬ģ de Yarza en trazas modernistas de principios del siglo XX, ocupado por el femenino Liceo Hispano, y con interesantes bajos comerciales. A‚Ēú‚Ėíos despu‚Ēú¬ģs fue demolido, y sustituido por un bloque de as‚Ēú¬ģptica e impersonal nueva planta moderna. Su vecino de la izquierda fue profundamente remodelado, aunque conserv‚Ēú‚Ēā la antigua traza de los balcones. Fuente visual: Estudio Coyne, AHPZ.', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65392600, -0.88085700, '0101000020E61000004A7CEE04FB2FECBF8600E0D8B3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31511956432.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31511956432.webp', 'https://www.flickr.com/photos/zaragozaantigua/31511956432/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23441, 'Plaza de San Felipe 1951', '"Plaza de San Felipe [Calle Torre Nueva]." A la izquierda, el entronque de la plaza con la calle de Torre Nueva y lateral derecho del edificio del Torre‚Ēú‚Ēān Fortea. A la derecha, el retranqueado inmueble del n‚Ē¨‚ēĎ 31 (accesorio a los n‚Ēú‚ēĎmeros 1-3 de la calle de Mat‚Ēú¬°as Carrica, antigua de la Luna), que posiblemente fuera la antigua casa de Jer‚Ēú‚Ēānimo Urrea, y que en el momento de realizar la fotograf‚Ēú¬°a era propiedad de los hijos de Pedro La‚Ēú¬°n como negocio de venta de cueros. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CENTRO', 41.65471700, -0.88189900, '0101000020E6100000DA006C408438ECBF4F9143C4CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14897694220.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14897694220.webp', 'https://www.flickr.com/photos/zaragozaantigua/14897694220/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23442, 'Pl. de San Felipe 1967', 'Imagen centrada en la rotunda fachada del Torre‚Ēú‚Ēān Fortea, o antigua casa de los Cerd‚Ēú√≠n de Escatr‚Ēú‚Ēān, de f‚Ēú√≠brica bajomedieval con modificaciones en los siglos XV y XVI. Fuente visual: fotograf‚Ēú¬°a de Guillermo Fat‚Ēú√≠s Ojuel en Torralba, Federico; G‚Ēú‚Ēāmez de Valenzuela, Manuel, Cat‚Ēú√≠logo de monumentos hist‚Ēú‚Ēāricos-art‚Ēú¬°sticos y edificios de inter‚Ēú¬ģs para el estudio del arte en la ciudad de Zaragoza, Bolet‚Ēú¬°n municipal de Zaragoza, 1967.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.65485300, -0.88200200, '0101000020E6100000003620425C39ECBF00581D39D2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14938069891.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14938069891.webp', 'https://www.flickr.com/photos/zaragozaantigua/14938069891/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
