ÔĽŅINSERT INTO public.photos VALUES (21371, 'Sal‚Ēú‚Ēān Fuenclara c.1915', '"Retrato de grupo de ni‚Ēú‚Ėías disfrazadas en el Patio de luces del cine Fuenclara". El cine Fuenclara (calle Fuenclara, 2) comenz‚Ēú‚Ēā a funcionar en 1915 en lo que hasta entonces hab‚Ēú¬°a sido teatro ("Sal‚Ēú‚Ēān Fuenclara"), con capacidad para unas 500 personas. Las sesiones infantiles, como la de la imagen, eran a las 17 h., en funciones organizadas por las "Escuelas Dominicales", a cargo de las Se‚Ēú‚Ėíoritas Instructoras. Tras la proclamaci‚Ēú‚Ēān de la Segunda Rep‚Ēú‚ēĎblica democr‚Ēú√≠tica espa‚Ēú‚Ėíola, en el sal‚Ēú‚Ēān del teatro tuvieron lugar m‚Ēú¬°tines y actos pol‚Ēú¬°ticos de "afirmaci‚Ēú‚Ēān cat‚Ēú‚Ēālica", como el que tuvo lugar el 9 de noviembre de ese a‚Ēú‚Ėío. Desde la venida de la columna, en m‚Ēú√≠rmol mortal, la religi‚Ēú‚Ēān cat‚Ēú‚Ēālica y la pol‚Ēú¬°tica nunca han dejado de ir de la mano en esta ciudad, con todo lo que ello implica. En la d‚Ēú¬ģcada siguiente, antes de convertirse en cine, continu‚Ēú‚Ēā siendo utilizado como local de teatro, por ejemplo, por la Asociaci‚Ēú‚Ēān de los J‚Ēú‚Ēāvenes de Acci‚Ēú‚Ēān Cat‚Ēú‚Ēālica (Centro de la Seo), en horario ya no tan infantil (22.00 h). Fuente visual: Archivo Municipal. Francisco G‚Ēú‚Ēārriz (Donaci‚Ēú‚Ēān Palacio Fuenclara).', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.65394400, -0.88230200, '0101000020E6100000A7406667D13BECBF2DB5DE6FB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15420945139.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15420945139.webp', 'https://www.flickr.com/photos/zaragozaantigua/15420945139/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
